        if (!input) {
            console.log("ERR Input is empty");
            return;
        }

        let parsedInput;
        try {
            parsedInput = JSON.parse(input);
        } catch (err: any) {
            console.log(`ERR Invalid JSON input: ${err.message || err}`);
